import{j as e}from"./ui-vendor-CUvJdy9K.js";import{S as t}from"./ServicePageTemplate-DK88ALIG.js";import{W as r}from"./wrench-CqJdlyNw.js";import"./react-vendor-CSY-tL5Y.js";import"./index-CNKyEhcU.js";import"./Footer-BvlMLj9q.js";import"./phone-BivoBbWr.js";import"./AnimatedSection-01g3Hqv0.js";import"./breadcrumb-Bp3alA4N.js";import"./index-wnGSTn9f.js";import"./utils-BLSKlp9E.js";import"./sections-CZ_nPSTs.js";import"./accordion-DIYFdwAK.js";import"./circle-check-big-CCS8Sa3O.js";const f=()=>e.jsx(t,{title:"Underhåll & Support",metaTitle:"Webbunderhåll & support Västmanland | LRH Konsult",metaDescription:"Personlig webbsupport och underhåll i Västmanland. Dagliga backuper, säkerhetsuppdateringar och dygnet-runt-övervakning för företag i Västerås.",heroSubheading:"Underhåll & Support",heroHeading:"Underhåll & Support – trygg webbdrift",heroDescription:"Lämna det tekniska till oss. Vi erbjuder marknadens tryggaste underhåll och support för företag i hela Västmanlands län. Vi ser till att din hemsida alltid är uppdaterad, snabb och skyddad mot digitala hot.",whyTitle:"Din lokala webbpartner i Västmanland",whyText:"Med personlig support från Västmanland får du hjälp direkt när du behöver det. Vi övervakar din sajt dygnet runt och agerar proaktivt för att förhindra problem innan de uppstår – så att du kan fokusera fullt ut på att driva din verksamhet.",icon:r,breadcrumbLabel:"Underhåll & Support",features:[{title:"Dagliga backuper",description:"Automatiska dagliga backuper med snabb återställning inom 15 minuter om något skulle gå fel."},{title:"Säkerhetsuppdateringar",description:"Regelbundna uppdateringar av CMS, plugins och server för att stänga säkerhetshål och hålla systemet aktuellt."},{title:"Övervakning dygnet runt",description:"Uptime-monitoring som larmar direkt om din sajt går ner – med snabb åtgärd och minimal nertid."},{title:"Teknisk support",description:"Snabb hjälp med innehållsuppdateringar, buggfixar, nya funktioner och tekniska frågor."},{title:"Månadsrapport",description:"Tydlig rapport varje månad med status, genomförda uppdateringar, prestanda-data och rekommendationer."}],faqTitle:"Vanliga frågor om webbunderhåll",faq:[{question:"Vad händer om min hemsida går ner?",answer:"Vi övervakar sajten dygnet runt och återställer den direkt från våra dagliga backuper om något sker. Du får ett larm och statusuppdatering inom minuter."},{question:"Hjälper ni till med e-post och domäner också?",answer:"Ja, vi kan hantera hela din digitala infrastruktur – domäner, e-post, hosting och DNS – för en krångelfri vardag."},{question:"Hur kontaktar jag supporten?",answer:"Du når oss via mejl eller telefon. Vi finns lokalt i Västmanland för snabb hantering och personlig kontakt."},{question:"Kan ni ta över en sajt byggd av annan byrå?",answer:"Ja, vi tar regelbundet över webbplatser från andra leverantörer. Vi gör alltid en teknisk genomgång först för att säkerställa full kontroll."}],testimonial:{quote:"Vi sover gott om natten nu. Lucas sköter allt tekniskt och vi kan fokusera på våra kunder istället.",author:"Peter Nilsson",role:"VD, Nilssons Fastigheter"},contentSections:[{title:"Kundcase: Trygg drift för fastighetsbolag",paragraphs:["Ett fastighetsbolag i Västerås med flera hundra hyresgäster förlitade sig på sin webbplats för felanmälningar, kontaktformulär och information. När sajten gick ner under en helg förlorade de viktiga felanmälningar och fick hantera frustrerade hyresgäster via telefon under måndagen. Det blev tydligt att de behövde en pålitligare lösning.","Vi tog över driften och implementerade ett komplett övervaknings- och backupsystem. Sajten övervakas nu dygnet runt med automatiska larm vid driftstörningar, dagliga backuper med möjlighet till återställning inom 15 minuter, samt månatliga säkerhetsuppdateringar av alla komponenter.","Sedan vi tog över har sajten haft 99,98 % upptid och bolaget har inte missat en enda felanmälan. Den proaktiva övervakningen har dessutom identifierat och åtgärdat potentiella problem innan de påverkat användarna."]},{title:"Vad ingår i professionellt webbunderhåll?",paragraphs:["Professionellt webbunderhåll handlar om mer än att bara hålla sajten igång. Det handlar om att proaktivt skydda din investering och säkerställa att din webbplats fortsätter att prestera optimalt. En sajt som inte underhålls regelbundet blir gradvis långsammare, mer sårbar för attacker och tappar ranking i sökmotorerna.","Våra månadsavtal inkluderar dagliga backuper, säkerhetsuppdateringar, uptime-övervakning med automatiska larm, teknisk support via mejl och telefon, samt en månadsrapport med status och rekommendationer. Vi anpassar alltid paketet efter din verksamhets specifika behov och budget.","Kan ni ta över driften av en sajt som någon annan har byggt? Ja, vi tar regelbundet över webbplatser som byggts av andra byråer eller frilansare. Vi börjar alltid med en teknisk genomgång för att identifiera eventuella problem, säkerhetsluckor och prestandaflaskhalsar innan vi lägger in sajten i vårt övervaknings- och underhållssystem."]}],relatedServices:[{label:"Prestanda-optimering",href:"/tjanster/prestanda-optimering"},{label:"WordPress-lösningar",href:"/tjanster/wordpress-losningar"},{label:"Webbutveckling",href:"/tjanster/webbutveckling"}]});export{f as default};
